export const CLIENT_SW = "const BUILD_HASH = '17beff676d7b'\nconst CACHE_NAME = `cepheus-online-${BUILD_HASH}`\nconst PRECACHE_URLS = [\n  '/',\n  '/client.js',\n  `/client.js?v=${BUILD_HASH}`,\n  '/client/app/app.js',\n  `/client/app/app.js?v=${BUILD_HASH}`,\n  '/styles.css',\n  `/styles.css?v=${BUILD_HASH}`,\n  '/icon.svg',\n  '/icon-maskable.svg',\n  '/favicon.svg',\n  '/site.webmanifest',\n  '/manifest.webmanifest',\n  '/manifest.json'\n]\n\nconst isDynamicRequest = (event, url) =>\n  event.request.method !== 'GET' ||\n  url.pathname.startsWith('/rooms/') ||\n  url.pathname.startsWith('/api/') ||\n  url.pathname === '/health' ||\n  url.pathname === '/api/health' ||\n  url.pathname === '/sw.js'\n\nconst isClientAssetRequest = (url) =>\n  url.pathname.startsWith('/client/') ||\n  url.pathname === '/client.js' ||\n  url.pathname === '/styles.css'\n\nconst fetchAndCache = (request) =>\n  fetch(request).then((response) => {\n    if (response.ok) {\n      const copy = response.clone()\n      caches.open(CACHE_NAME).then((cache) => cache.put(request, copy))\n    }\n    return response\n  })\n\nself.addEventListener('install', (event) => {\n  event.waitUntil(\n    caches.open(CACHE_NAME).then((cache) => cache.addAll(PRECACHE_URLS))\n  )\n})\n\nself.addEventListener('message', (event) => {\n  if (event.data && event.data.type === 'SKIP_WAITING') {\n    event.waitUntil(self.skipWaiting())\n  }\n})\n\nself.addEventListener('activate', (event) => {\n  event.waitUntil(\n    caches\n      .keys()\n      .then((keys) =>\n        Promise.all(\n          keys\n            .filter((key) => key !== CACHE_NAME)\n            .map((key) => caches.delete(key))\n        )\n      )\n      .then(() => self.clients.claim())\n      .then(() =>\n        self.clients.matchAll().then((clients) => {\n          for (const client of clients) {\n            client.postMessage({ type: 'SW_UPDATED', buildHash: BUILD_HASH })\n          }\n        })\n      )\n  )\n})\n\nself.addEventListener('fetch', (event) => {\n  const url = new URL(event.request.url)\n  if (isDynamicRequest(event, url)) return\n\n  if (isClientAssetRequest(url)) {\n    event.respondWith(\n      fetchAndCache(event.request).catch(() => caches.match(event.request))\n    )\n    return\n  }\n\n  if (event.request.mode === 'navigate') {\n    event.respondWith(\n      fetch(event.request)\n        .then((response) => {\n          if (response.ok) {\n            const copy = response.clone()\n            caches.open(CACHE_NAME).then((cache) => cache.put('/', copy))\n          }\n          return response\n        })\n        .catch(() =>\n          caches\n            .match(event.request)\n            .then((cached) => cached || caches.match('/'))\n        )\n    )\n    return\n  }\n\n  event.respondWith(\n    caches.match(event.request).then((cached) => {\n      const fetched = fetchAndCache(event.request).catch(() => cached)\n\n      return cached || fetched\n    })\n  )\n})\n"

